// Anthology Drive Broker -- authorize, validate, ROUTE the full action set.
// Trevor's Google service-account credential lives ONLY inside this n8n instance and
// never leaves it. The client box holds only the webhook URL + a low-privilege shared
// token (validated HERE). Per-Doc + participant-tree + capabilities all route from here.
const EXPECTED = $env.ANTHOLOGY_DRIVE_BROKER_TOKEN || '';
const ROOT = $env.ANTHOLOGY_DRIVE_ROOT_FOLDER || '';
const item = $input.first();
const j = (item && item.json) ? item.json : {};
const body = j.body || {};
const headers = j.headers || {};
const presented = headers['x-anthology-broker-token'] || headers['X-Anthology-Broker-Token'] || body.token || '';

const DOC_ACTIONS = ['create_doc', 'upload_pdf', 'share_doc_edit', 'pull_doc_text'];
const TREE_ACTIONS = ['create_book_tree', 'create_participant_tree'];
const IMPLEMENTED = TREE_ACTIONS.concat(DOC_ACTIONS);

function respond(code, obj) {
  return [{ json: { route: 'respond', http_code: code, response: obj } }];
}
function reject(code, error, extra) {
  return respond(code, Object.assign({ ok: false, error: error }, extra || {}));
}
const qesc = (s) => String(s).replace(/\\/g, '\\\\').replace(/'/g, "\\'");

if (!EXPECTED) return reject(500, 'broker_misconfigured', { detail: 'ANTHOLOGY_DRIVE_BROKER_TOKEN not set in n8n' });
if (!presented || presented !== EXPECTED) return reject(401, 'unauthorized');

const action = (body.action || '').toString();
if (!action) return reject(400, 'missing_action');

// capabilities probe -- the broker-preflight asks which actions this workflow implements.
if (action === 'capabilities') {
  return respond(200, { ok: true, action: 'capabilities', via: 'n8n_broker', implemented_actions: IMPLEMENTED });
}
if (IMPLEMENTED.indexOf(action) === -1) {
  return reject(400, 'unknown_action', { action: action });
}
// side-effect-free probe of a known action (broker-preflight fallback path).
if (body.probe === true) {
  return respond(200, { ok: true, action: action, via: 'n8n_broker', probe: true, implemented: true });
}

function need(fields) {
  const missing = [];
  for (const f of fields) { if (!(body[f] != null && String(body[f]).trim() !== '')) missing.push(f); }
  return missing;
}
function shareRole(mode) {
  if (mode === 'edit') return 'writer';
  if (mode === 'view') return 'reader';
  return '';
}

if (action === 'create_book_tree') {
  if (!ROOT) return reject(500, 'broker_misconfigured', { detail: 'ANTHOLOGY_DRIVE_ROOT_FOLDER not set in n8n' });
  const m = need(['client_key', 'producer_email', 'book_title']);
  if (m.length) return reject(400, 'missing_fields', { missing: m });
  const client_key = body.client_key.toString().trim();
  const producer_email = body.producer_email.toString().trim();
  const book_title = body.book_title.toString().trim();
  const co_author = (body.co_author || '').toString().trim();
  return [{ json: {
    route: 'book_tree', action: action, root_folder_id: ROOT,
    client_key, producer_email, book_title, co_author,
    client_folder_name: client_key, producer_folder_name: producer_email, book_folder_name: book_title,
    q_client: qesc(client_key), q_producer: qesc(producer_email), q_book: qesc(book_title)
  } }];
}

if (action === 'create_participant_tree') {
  if (!ROOT) return reject(500, 'broker_misconfigured', { detail: 'ANTHOLOGY_DRIVE_ROOT_FOLDER not set in n8n' });
  const m = need(['producer', 'anthology', 'participant']);
  if (m.length) return reject(400, 'missing_fields', { missing: m });
  const producer = body.producer.toString().trim();
  const anthology = body.anthology.toString().trim();
  const participant = body.participant.toString().trim();
  return [{ json: {
    route: 'participant_tree', action: action, root_folder_id: ROOT,
    producer, anthology, participant,
    producer_folder_name: producer, anthology_folder_name: anthology, participant_folder_name: participant,
    q_producer: qesc(producer), q_anthology: qesc(anthology), q_participant: qesc(participant)
  } }];
}

if (action === 'create_doc') {
  const m = need(['parent_folder_id', 'name']);
  if (m.length) return reject(400, 'missing_fields', { missing: m });
  const share_mode = (body.share_mode || '').toString();
  return [{ json: {
    route: 'create_doc', action: action,
    parent_folder_id: body.parent_folder_id.toString().trim(),
    doc_name: body.name.toString().trim(),
    doc_text: (body.text != null ? String(body.text) : ''),
    share_mode: share_mode || null, share_role: shareRole(share_mode)
  } }];
}

if (action === 'upload_pdf') {
  const m = need(['parent_folder_id', 'name', 'content_b64']);
  if (m.length) return reject(400, 'missing_fields', { missing: m });
  const share_mode = (body.share_mode || '').toString();
  return [{ json: {
    route: 'upload_pdf', action: action,
    parent_folder_id: body.parent_folder_id.toString().trim(),
    file_name: body.name.toString().trim(),
    content_b64: body.content_b64.toString(),
    mime: (body.mime || 'application/octet-stream').toString(),
    share_mode: share_mode || null, share_role: shareRole(share_mode)
  } }];
}

if (action === 'share_doc_edit') {
  const m = need(['file_id', 'share_mode']);
  if (m.length) return reject(400, 'missing_fields', { missing: m });
  const share_mode = body.share_mode.toString();
  const role = shareRole(share_mode);
  if (!role) return reject(400, 'bad_share_mode', { share_mode: share_mode });
  return [{ json: { route: 'share_doc_edit', action: action,
    file_id: body.file_id.toString().trim(), share_mode, share_role: role } }];
}

if (action === 'pull_doc_text') {
  const m = need(['doc_id']);
  if (m.length) return reject(400, 'missing_fields', { missing: m });
  return [{ json: { route: 'pull_doc_text', action: action, doc_id: body.doc_id.toString().trim() } }];
}

return reject(400, 'unknown_action', { action: action });

const j = $input.first().json;
const id = j.id || (j.files && j.files[0] && j.files[0].id) || '';
if (!id) throw new Error('client folder id could not be resolved');
return [{ json: { folderId: id, level: 'client' } }];

const j = $input.first().json;
const id = j.id || (j.files && j.files[0] && j.files[0].id) || '';
if (!id) throw new Error('producer folder id could not be resolved');
return [{ json: { folderId: id, level: 'producer' } }];

const j = $input.first().json;
const id = j.id || (j.files && j.files[0] && j.files[0].id) || '';
if (!id) throw new Error('book folder id could not be resolved');
return [{ json: { folderId: id, level: 'book' } }];

const a = $('Authorize & Dispatch').item.json;
return [{ json: {
  ok: true, action: 'create_book_tree', via: 'n8n_broker',
  client_key: a.client_key, producer_email: a.producer_email, book_title: a.book_title,
  root_folder_id: a.root_folder_id,
  client_folder_id: $('Client Resolved').item.json.folderId,
  producer_folder_id: $('Producer Resolved').item.json.folderId,
  book_folder_id: $('Book Resolved').item.json.folderId,
  producer_editor_shared: true
} }];

const j = $input.first().json;
const id = j.id || (j.files && j.files[0] && j.files[0].id) || '';
if (!id) throw new Error('producer folder id could not be resolved');
return [{ json: { folderId: id, level: 'producer' } }];

const j = $input.first().json;
const id = j.id || (j.files && j.files[0] && j.files[0].id) || '';
if (!id) throw new Error('anthology folder id could not be resolved');
return [{ json: { folderId: id, level: 'anthology' } }];

const j = $input.first().json;
const id = j.id || (j.files && j.files[0] && j.files[0].id) || '';
if (!id) throw new Error('participant folder id could not be resolved');
return [{ json: { folderId: id, level: 'participant' } }];

const a = $('Authorize & Dispatch').item.json;
return [{ json: {
  ok: true, action: 'create_participant_tree', via: 'n8n_broker',
  root_folder_id: a.root_folder_id,
  producer: a.producer, anthology: a.anthology, participant: a.participant,
  producer_folder_id: $('PT Producer Resolved').item.json.folderId,
  anthology_folder_id: $('PT Anthology Resolved').item.json.folderId,
  participant_folder_id: $('PT Participant Resolved').item.json.folderId
} }];

const a = $('Authorize & Dispatch').item.json;
const f = $input.first().json;
const perm = (() => { try { return $('CD Share').item.json.id; } catch (e) { return null; } })();
return [{ json: { ok: true, action: 'create_doc', via: 'n8n_broker',
  doc_id: $('CD Create Doc').item.json.id, doc_url: f.webViewLink, name: f.name,
  share_mode: a.share_mode, permission_id: perm } }];

const a = $('Authorize & Dispatch').item.json;
return [{ json: { fileId: $('UP Create File').item.json.id },
  binary: { data: { data: a.content_b64, mimeType: a.mime, fileName: a.file_name } } }];

const a = $('Authorize & Dispatch').item.json;
const f = $input.first().json;
const perm = (() => { try { return $('UP Share').item.json.id; } catch (e) { return null; } })();
return [{ json: { ok: true, action: 'upload_pdf', via: 'n8n_broker',
  file_id: $('UP Create File').item.json.id, drive_url: f.webViewLink,
  download_url: f.webContentLink, name: f.name, share_mode: a.share_mode, permission_id: perm } }];

const a = $('Authorize & Dispatch').item.json;
const f = $input.first().json;
return [{ json: { ok: true, action: 'share_doc_edit', via: 'n8n_broker',
  file_id: a.file_id, share_mode: a.share_mode,
  permission_id: $('SD Share').item.json.id, view_url: f.webViewLink } }];

const a = $('Authorize & Dispatch').item.json;
const r = $input.first().json;
const text = (r && typeof r.data === 'string') ? r.data : (typeof r === 'string' ? r : '');
return [{ json: { ok: true, action: 'pull_doc_text', via: 'n8n_broker',
  doc_id: a.doc_id, text: text } }];
